def verify_signature(payload, signature, timestamp):
    """Verify HMAC signature of the webhook payload"""
    if not signature:
        return False
    
    message = f"{timestamp}.{payload}".encode('utf-8')
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        message,
        hashlib.sha256
    ).hexdigest()
    
